import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise';

const vex = new Vex({
  projectId: 'edu-flowise-project',
  apiKey: process.env.VEX_API_KEY
});

const flowConfig = {
  nodes: [...],
  callbacks: {
    onChainEnd: async (output: any) => {
      const result = await vex.validate({
        input: output.input,
        output: output.text,
        policy: 'education-ferpa',
        context: { studentAge: output.metadata?.age, consentGiven: output.metadata?.consent }
      });
      if (!result.valid) {
        throw new Error(`FERPA violation: ${result.issues[0].message}`);
      }
      return output;
    }
  }
};

const retrieverCallback = async (docs: Document[]) => {
  const vex = new Vex({ projectId: 'edu-rag' });
  const filteredDocs = await Promise.all(
    docs.map(async (doc) => {
      const validation = await vex.validate({
        input: doc.pageContent,
        policy: 'education-pii-redaction',
        metadata: { source: 'student-portal', relevanceScore: doc.metadata.similarity }
      });
      return validation.valid ? doc : null;
    })
  );
  return filteredDocs.filter(Boolean);
};

// In Flowise vector store node
vectorStoreNode.setRetrieverCallback(retrieverCallback);

const agentHandoffCallback = async (context: any, nextAgentInput: any) => {
  const vex = new Vex({ projectId: 'multi-agent-edu' });

  const stateCheck = await vex.validate({
    input: nextAgentInput,
    context: context,
    policy: 'education-consent-propagation',
    rules: [
      'require:context.consent_given',
      'require:context.student_id_anonymized',
      'block_if:context.age < 13 && !context.parental_consent'
    ]
  });

  if (!stateCheck.valid) {
    return { error: 'Consent validation failed', issues: stateCheck.issues };
  }

  return { ...nextAgentInput, preservedContext: context };
};
